      </main>

      <footer class="mt-6 flex flex-col items-center justify-between gap-3 border-t border-white/10 px-2 py-4 text-xs text-white/55 sm:flex-row">
        <p>© {{ currentYear }} Embedded Payments. Built for a modern checkout experience.</p>
        <p>Secure by design · Responsive · Fast confirmation</p>
      </footer>

      <RefundDialog
        v-model="showRefundRequestDialog"
        :currency="currency"
        :transaction-amount="total"
        :processing="isSubmittingRefundRequest"
        :server-error="refundRequestError"
        eyebrow="Customer refund request"
        title="Request a refund"
        description="Tell us why you'd like to request a refund for this transaction."
        amount-label="Requested amount"
        amount-help-text="Enter the amount you want to request back. It can be full or partial."
        reason-label="Message"
        reason-placeholder="Explain the issue or reason for the request"
        reason-help-text="This message will be associated with your transaction refund request."
        confirm-label="Submit request"
        processing-label="Submitting…"
        cancel-label="Cancel"
        request-type-label="Full refund"
        @confirm="submitRefundRequest"
      />
      </template>
