</template>

<script setup lang="ts">
import { computed, reactive, ref, onMounted } from 'vue'
import { watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import {
  CircleCheckBig,
  CreditCard,
  LockKeyhole,
  ShieldCheck,
  Sparkles,
} from 'lucide-vue-next'
import RefundDialog from '@/components/shared/RefundDialog.vue'
import { getPaymentIntent, submitCheckoutPayment, type PaymentIntent, type CheckoutSubmitResponse } from '@/services/checkout'
import { refundService } from '@/services/refunds'
import { authService } from '@/services/auth'
import { useAuthStore } from '@/stores/auth'
import { useNotificationStore } from '@/stores/notifications'
import type { Refund } from '@/types'

const route = useRoute()
const authStore = useAuthStore()
const notificationStore = useNotificationStore()

const currentYear = new Date().getFullYear()

// Loading states
const isLoading = ref(true)
const isProcessing = ref(false)
const paymentCompleted = ref(false)
const errorMessage = ref('')

// Payment intent data from backend
const paymentIntent = ref<PaymentIntent | null>(null)
const transactionData = ref<CheckoutSubmitResponse | null>(null)
const refundRequest = ref<Refund | null>(null)
const showRefundRequestDialog = ref(false)
const isSubmittingRefundRequest = ref(false)
const refundRequestError = ref<string | null>(null)
const showCustomerSignIn = ref(false)
const customerSignInEmail = ref('')
const isCustomerSigningIn = ref(false)
const customerToken = ref<string | null>(null)

// Computed properties for display
const merchantName = computed(() => paymentIntent.value?.merchantName || 'Merchant')
const description = computed(() => paymentIntent.value?.description || 'One-time secure payment')
const sessionLabel = computed(() => route.params.checkoutId ? `Order ${String(route.params.checkoutId).substring(0, 8)}...` : 'Checkout')
const canSubmitRefundRequest = computed(() => !!transactionData.value?.transactionId && authStore.isAuthenticated)

const subtotal = computed(() => paymentIntent.value?.amount || 0)
const currency = computed(() => paymentIntent.value?.currency?.toUpperCase() || 'USD')
const processingFee = computed(() => subtotal.value * 0.029 + 0.3)
const total = computed(() => subtotal.value + processingFee.value)

const formattedSubtotal = computed(() => formatMoney(subtotal.value, currency.value))
const formattedFee = computed(() => formatMoney(processingFee.value, currency.value))
const formattedTotal = computed(() => formatMoney(total.value, currency.value))

const form = reactive({
  cardholderName: '',
  cardNumber: '',
  expiry: '',
  cvc: '',
  email: '',
})

const receipt = reactive({
  reference: '',
  transactionId: '',
  last4: '4242',
  paidAt: '',
})

// Utility functions
function formatMoney(amount: number, code: string) {
  try {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: code,
      maximumFractionDigits: 2,
    }).format(amount)
  } catch {
    return `${code} ${amount.toFixed(2)}`
  }
}

function handleCardNumberInput(event: Event) {
  const target = event.target as HTMLInputElement
  const digits = target.value.replace(/\D/g, '').slice(0, 16)
  const groups = digits.match(/.{1,4}/g) ?? []
  form.cardNumber = groups.join(' ')
}

function handleExpiryInput(event: Event) {
  const target = event.target as HTMLInputElement
  const digits = target.value.replace(/\D/g, '').slice(0, 4)
  if (digits.length <= 2) {
    form.expiry = digits
    return
  }
  form.expiry = `${digits.slice(0, 2)}/${digits.slice(2)}`
}

function stepClass(step: number) {
  const activeStep = paymentCompleted.value ? 3 : isProcessing.value ? 2 : 1
  return [
    'rounded-full px-3 py-2 text-center transition',
    step === activeStep ? 'bg-slate-950 text-white shadow-sm' : 'bg-slate-100 text-slate-500',
  ]
}

const router = useRouter()

function openRefundRequestDialog() {
  if (!canSubmitRefundRequest.value) {
    // show inline customer sign-in form to obtain a temporary token for refund request
    showCustomerSignIn.value = true
    return
  }

  refundRequestError.value = null
  showRefundRequestDialog.value = true
}

function redirectToLoginWithReturnTo() {
  const current = window.location.pathname + window.location.search
  const separator = current.includes('?') ? '&' : '?'
  const target = `${current}${separator}openRefund=true`
  router.push({ path: '/login', query: { returnTo: target } })
}

async function submitRefundRequest(payload: { amount: number; reason: string }) {
  if (!transactionData.value?.transactionId) {
    refundRequestError.value = 'Transaction reference is not available yet.'
    return
  }

  if (!authStore.isAuthenticated) {
    refundRequestError.value = 'You must sign in before submitting a refund request.'
    notificationStore.warning(refundRequestError.value)
    return
  }

  isSubmittingRefundRequest.value = true
  refundRequestError.value = null

  try {
    let createdRefund: Refund
    if (customerToken.value) {
      createdRefund = await refundService.requestByCustomerWithToken({
        transactionId: transactionData.value.transactionId,
        amount: payload.amount,
        reason: payload.reason,
      }, customerToken.value)
    } else {
      createdRefund = await refundService.requestByCustomer({
        transactionId: transactionData.value.transactionId,
        amount: payload.amount,
        reason: payload.reason,
      })
    }

    refundRequest.value = createdRefund
    showRefundRequestDialog.value = false
    notificationStore.success('Refund request submitted successfully')
  } catch (error: any) {
    const message = error.response?.data?.message || 'Failed to submit refund request'
    refundRequestError.value = message
    notificationStore.error(message)
  } finally {
    isSubmittingRefundRequest.value = false
  }
}

async function submitCustomerSignIn() {
  if (!transactionData.value?.transactionId) {
    notificationStore.error('Transaction id not available yet')
    return
  }
  if (!customerSignInEmail.value || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(customerSignInEmail.value)) {
    notificationStore.error('Please enter a valid email')
    return
  }

  isCustomerSigningIn.value = true
  try {
    const resp = await authService.issueCustomerToken(transactionData.value.transactionId, customerSignInEmail.value)
    customerToken.value = resp.token
    notificationStore.success('Signed in as customer')
    showCustomerSignIn.value = false
    // open refund dialog now that we have a token
    showRefundRequestDialog.value = true
  } catch (error: any) {
    const message = error.response?.data?.message || 'Failed to sign in as customer'
    notificationStore.error(message)
  } finally {
    isCustomerSigningIn.value = false
  }
}

function validateForm() {
  if (!form.cardholderName.trim()) return 'Cardholder name is required'
  if (!/^\d{4} \d{4} \d{4} \d{4}$/.test(form.cardNumber)) return 'Card number must have 16 digits'
  if (!/^\d{2}\/\d{2}$/.test(form.expiry)) return 'Expiry must be in MM/YY format'
  if (!/^\d{3,4}$/.test(form.cvc)) return 'CVC must contain 3 or 4 digits'
  if (!form.email.trim() || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) return 'Enter a valid email address'
  return ''
}

async function loadPaymentIntent() {
  if (!route.params.checkoutId) {
    errorMessage.value = 'No payment intent specified. Please use a valid checkout link.'
    isLoading.value = false
    return
  }

  try {
    const intent = await getPaymentIntent(route.params.checkoutId as string)
    paymentIntent.value = intent
    notificationStore.success(`Payment intent loaded: ${formatMoney(intent.amount, intent.currency)}`)
    // If the payment intent is already completed, show the success/receipt view
    if (intent.status === 'SUCCEEDED' || intent.status === 'SUCCEEDED'.toLowerCase()) {
      paymentCompleted.value = true
      // Populate a minimal receipt so the UI shows meaningful info
      receipt.paidAt = new Intl.DateTimeFormat('en-US', { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(intent.updatedAt))
      receipt.reference = ''
      // transactionId is not exposed by the public intent endpoint; leave empty.
      receipt.transactionId = ''
    }
  } catch (error: any) {
    const status = error.response?.status
    if (status === 404) {
      errorMessage.value = 'Payment intent not found. Please check the checkout link.'
    } else if (status === 410) {
      errorMessage.value = 'This payment intent is no longer available.'
    } else {
      errorMessage.value = 'Failed to load payment intent. Please try again.'
    }
    notificationStore.error(errorMessage.value)
  } finally {
    isLoading.value = false
  }
}

async function submitPayment() {
  errorMessage.value = validateForm()
  if (errorMessage.value) return

  if (!paymentIntent.value) {
    errorMessage.value = 'Payment intent not loaded'
    return
  }

  isProcessing.value = true
  errorMessage.value = ''

  try {
    const response = await submitCheckoutPayment({
      checkoutId: paymentIntent.value.id,
      customerEmail: form.email,
      customerName: form.cardholderName,
    })

    transactionData.value = response

    if (response.status === 'SUCCEEDED') {
      paymentCompleted.value = true
      // Use backend-generated references instead of local mock references.
      receipt.reference = response.processorReference || response.transactionId
      receipt.transactionId = response.transactionId
      receipt.last4 = form.cardNumber.replace(/\s/g, '').slice(-4)
      receipt.paidAt = new Intl.DateTimeFormat('en-US', {
        dateStyle: 'medium',
        timeStyle: 'short',
      }).format(new Date())
      notificationStore.success(`Payment successful! Transaction ID: ${response.transactionId}`)
    } else {
      errorMessage.value = 'Payment processing failed. Please try again.'
      notificationStore.error(errorMessage.value)
    }
  } catch (error: any) {
    const status = error.response?.status

    if (status === 409) {
      errorMessage.value = 'A transaction is already in progress for this intent.'
    } else if (status === 422) {
      errorMessage.value = 'This payment intent cannot be processed.'
    } else if (status === 500) {
      errorMessage.value = 'Payment processing error. Please try again.'
    } else {
      errorMessage.value = 'We could not complete the payment. Please try again.'
    }
    notificationStore.error(errorMessage.value)
  } finally {
    isProcessing.value = false
  }
}

function resetCheckout() {
  paymentCompleted.value = false
  errorMessage.value = ''
  refundRequest.value = null
  showRefundRequestDialog.value = false
  refundRequestError.value = null
  form.cardholderName = ''
  form.cardNumber = ''
  form.expiry = ''
  form.cvc = ''
  form.email = ''
  receipt.reference = ''
  receipt.transactionId = ''
  receipt.last4 = '4242'
  receipt.paidAt = ''
}

// Load payment intent on component mount
onMounted(() => {
  loadPaymentIntent()
})

// Auto-open refund dialog when the transaction completes and `openRefund=true` is present in the return URL
watch(
  () => transactionData.value?.transactionId,
  (id) => {
    const openRefund = (route.query.openRefund as string | undefined) === 'true'
    if (id && openRefund) {
      if (authStore.isAuthenticated) {
        showRefundRequestDialog.value = true
      } else {
        // If not authenticated, redirect to login preserving returnTo so user returns with the same query
        router.push({ path: '/login', query: { returnTo: route.fullPath } })
      }
    }
  }
)
</script>



